import{_ as t,o as a,c as i,a2 as o}from"./chunks/framework.CHeM0PsO.js";const u=JSON.parse('{"title":"Desktop app shell (Tauri, macOS-first)","description":"","frontmatter":{"rfc":"0038","title":"Desktop app shell (Tauri, macOS-first)","status":"Accepted","date":"June 2026","author":"kasunben","scope":"sovereign-desktop (separate repo), docs, CLAUDE.md, packages/sdk","incorporated_into_plan":"Yes — epic tasks 17.1–17.6"},"headers":[],"relativePath":"rfcs/0038-desktop-app-shell.md","filePath":"rfcs/0038-desktop-app-shell.md"}'),d={name:"rfcs/0038-desktop-app-shell.md"};function s(n,e,r,l,c,p){return a(),i("div",null,[...e[0]||(e[0]=[o(`<h2 id="summary" tabindex="-1">Summary <a class="header-anchor" href="#summary" aria-label="Permalink to &quot;Summary&quot;">​</a></h2><p>A minimal desktop shell app (<code>sovereign-desktop</code>) built with Tauri 2.x. On first launch the user enters their self-hosted Sovereign instance URL; the shell loads that URL in a WebView and persists it for subsequent launches. Multiple instances are supported. macOS ships first; Windows and Linux follow with the same codebase.</p><p>This mirrors the mobile strategy (documented in CLAUDE.md and SRS §3.12) — same universal shell + instance URL model, same <code>sdk.device.*</code> abstraction for plugin developers, separate repository.</p><h2 id="motivation" tabindex="-1">Motivation <a class="header-anchor" href="#motivation" aria-label="Permalink to &quot;Motivation&quot;">​</a></h2><p>The PWA (v1) covers most desktop use cases but has limits: no persistent system presence, no OS-level notifications on macOS, no deep link scheme, no dock icon without a browser window open. A Tauri shell closes these gaps without requiring plugins to change — <code>sdk.device.*</code> handles environment routing.</p><p>Sovereign&#39;s self-hosted positioning also benefits from a native download: it signals permanence and trust in a way a browser tab does not, and aligns with how Nextcloud, Bitwarden, and Element present their desktop clients.</p><h2 id="current-state" tabindex="-1">Current state <a class="header-anchor" href="#current-state" aria-label="Permalink to &quot;Current state&quot;">​</a></h2><ul><li>PWA ships in v1 (RFC 0013, Task 0.5.1) — installable via browser on macOS/Windows.</li><li>Mobile strategy decided (CLAUDE.md, SRS §3.12) — Capacitor shell, <code>sovereign-mobile</code> repo, <code>sdk.device.*</code> abstraction.</li><li><code>sdk.device.*</code> is defined in <code>packages/sdk</code> — the abstraction layer already exists; a <code>&quot;desktop&quot;</code> environment check is not yet wired.</li><li>No Electron or Tauri references anywhere in the codebase or RFC corpus.</li></ul><h2 id="proposed-design" tabindex="-1">Proposed design <a class="header-anchor" href="#proposed-design" aria-label="Permalink to &quot;Proposed design&quot;">​</a></h2><h3 id="repository" tabindex="-1">Repository <a class="header-anchor" href="#repository" aria-label="Permalink to &quot;Repository&quot;">​</a></h3><p><code>sovereign-desktop</code> — separate repository under the Sovereign project, not in this monorepo. Same pattern as the planned <code>sovereign-mobile</code>. Developed and versioned independently of the platform.</p><h3 id="technology-tauri-2-x" tabindex="-1">Technology: Tauri 2.x <a class="header-anchor" href="#technology-tauri-2-x" aria-label="Permalink to &quot;Technology: Tauri 2.x&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Concern</th><th>Choice</th><th>Why</th></tr></thead><tbody><tr><td>Shell framework</td><td>Tauri 2.x</td><td>Minimal shell philosophy; system WebView; ~5 MB binary</td></tr><tr><td>WebView (macOS)</td><td>WKWebView (Safari/WebKit)</td><td>Already targeted by mobile PWA; no new compat surface</td></tr><tr><td>WebView (Windows)</td><td>WebView2 (Chromium-based)</td><td>Tauri default; good modern-Windows coverage</td></tr><tr><td>WebView (Linux)</td><td>WebKitGTK</td><td>Tauri default; acceptable for self-hosters on Linux</td></tr><tr><td>Shell logic</td><td>TypeScript (<code>@tauri-apps/api</code>)</td><td>Consistent with the rest of the stack; no Rust needed for v1</td></tr><tr><td>Native plugins</td><td>Tauri plugin system (post-v1)</td><td>Mirrors Capacitor&#39;s plugin pattern; add capabilities as needed</td></tr><tr><td>Build / release</td><td>Tauri CLI + GitHub Actions</td><td><code>.app</code> + <code>.dmg</code> macOS; <code>.exe</code>/<code>.msi</code> Windows; AppImage Linux</td></tr></tbody></table><h3 id="first-launch-onboarding-flow" tabindex="-1">First-launch onboarding flow <a class="header-anchor" href="#first-launch-onboarding-flow" aria-label="Permalink to &quot;First-launch onboarding flow&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>App opens</span></span>
<span class="line"><span>  └─ No instance URL stored?</span></span>
<span class="line"><span>       └─ Show onboarding screen</span></span>
<span class="line"><span>            └─ User enters instance URL (e.g. https://my.sovereign.example)</span></span>
<span class="line"><span>                 └─ Validate: GET /api/health → expect 200 + { status: &quot;ok&quot; }</span></span>
<span class="line"><span>                      ├─ Valid → persist URL → load URL in WebView</span></span>
<span class="line"><span>                      └─ Invalid → inline error, let user retry</span></span>
<span class="line"><span>  └─ URL stored?</span></span>
<span class="line"><span>       └─ Load stored URL directly in WebView</span></span></code></pre></div><p>Multiple instances stored as an ordered list; instance switcher UI deferred to implementation.</p><h3 id="shell-capabilities" tabindex="-1">Shell capabilities <a class="header-anchor" href="#shell-capabilities" aria-label="Permalink to &quot;Shell capabilities&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Capability</th><th>v1</th><th>Post-v1 (Tauri plugin)</th></tr></thead><tbody><tr><td>Instance URL onboarding</td><td>✅</td><td>—</td></tr><tr><td>Persistent URL storage</td><td>✅</td><td>—</td></tr><tr><td>WebView shell</td><td>✅</td><td>—</td></tr><tr><td>Multiple instance switcher</td><td>✅</td><td>—</td></tr><tr><td>macOS <code>.dmg</code> distribution</td><td>✅</td><td>—</td></tr><tr><td>Windows <code>.exe</code>/<code>.msi</code></td><td>✅</td><td>—</td></tr><tr><td>Linux <code>.AppImage</code>/<code>.deb</code></td><td>✅</td><td>—</td></tr><tr><td>System tray / menu bar</td><td>—</td><td><code>tauri-plugin-system-tray</code> (task 17.2)</td></tr><tr><td>OS-level notifications</td><td>—</td><td><code>tauri-plugin-notification</code> (task 17.2)</td></tr><tr><td>Deep link scheme</td><td>—</td><td><code>sovereign://</code> deep link plugin (task 17.3)</td></tr><tr><td>Keychain credential storage</td><td>—</td><td><code>tauri-plugin-stronghold</code> (task 17.4)</td></tr><tr><td>Auto-updater</td><td>—</td><td><code>tauri-plugin-updater</code> (task 17.5)</td></tr><tr><td>Mac App Store distribution</td><td>—</td><td>Sandbox entitlements + MAS CI (task 17.6)</td></tr></tbody></table><h3 id="device-api-tier-desktop" tabindex="-1">Device API tier (desktop) <a class="header-anchor" href="#device-api-tier-desktop" aria-label="Permalink to &quot;Device API tier (desktop)&quot;">​</a></h3><p>Same three-tier model as mobile:</p><table tabindex="0"><thead><tr><th>Tier</th><th>Technology</th><th>Works in browser?</th></tr></thead><tbody><tr><td>Web APIs</td><td>Standard browser APIs, work in WKWebView</td><td>✅</td></tr><tr><td>Tauri plugins</td><td>JS bridge to native OS capabilities (post-v1)</td><td>❌</td></tr><tr><td>SDK abstraction</td><td><code>sdk.device.*</code> — detects env, routes to right tier</td><td>✅</td></tr></tbody></table><p>Plugin developers call <code>sdk.device.*</code> only — identical contract to mobile. The SDK implementation adds a <code>&quot;desktop&quot;</code> environment check alongside existing <code>&quot;browser&quot;</code> / <code>&quot;native&quot;</code> (mobile) checks. No plugin code changes required.</p><h3 id="distribution" tabindex="-1">Distribution <a class="header-anchor" href="#distribution" aria-label="Permalink to &quot;Distribution&quot;">​</a></h3><ul><li><strong>v1:</strong> Direct download via GitHub Releases — <code>.dmg</code> (macOS), <code>.exe</code>/<code>.msi</code> (Windows), <code>.AppImage</code>/<code>.deb</code> (Linux).</li><li><strong>Post-v1:</strong> Mac App Store (requires Apple Developer account, sandboxing, notarization — deferred).</li></ul><p>macOS <code>.dmg</code> requires code signing + Gatekeeper notarization even for direct download (macOS 10.15+). Tauri&#39;s pipeline handles this via GitHub Actions secrets: <code>APPLE_CERTIFICATE</code>, <code>APPLE_CERTIFICATE_PASSWORD</code>, <code>APPLE_SIGNING_IDENTITY</code>, <code>APPLE_ID</code>, <code>APPLE_PASSWORD</code>.</p><h2 id="sdk-impact" tabindex="-1">SDK impact <a class="header-anchor" href="#sdk-impact" aria-label="Permalink to &quot;SDK impact&quot;">​</a></h2><p><code>packages/sdk</code> gains a <code>&quot;desktop&quot;</code> environment in <code>sdk.device.*</code> routing. No new public API surface — internal environment detection only. Semver: patch bump.</p><h2 id="alternatives-considered" tabindex="-1">Alternatives considered <a class="header-anchor" href="#alternatives-considered" aria-label="Permalink to &quot;Alternatives considered&quot;">​</a></h2><ul><li><strong>Electron:</strong> ~150 MB binary (bundles full Chromium); philosophically inconsistent with Sovereign&#39;s lightweight identity and the Capacitor choice for mobile. Rejected.</li><li><strong>PWA only:</strong> Already ships; insufficient — system tray, OS notifications, deep links, and keychain are not available to PWAs on macOS/Windows.</li><li><strong>Native Swift / SwiftUI:</strong> Platform-locked, requires Swift expertise, inconsistent with the TypeScript-throughout stack. Rejected.</li></ul><h2 id="open-questions" tabindex="-1">Open questions <a class="header-anchor" href="#open-questions" aria-label="Permalink to &quot;Open questions&quot;">​</a></h2><ol><li>Minimum macOS version target — 13 (Ventura) or 12 (Monterey)?</li><li>Onboarding screen: local HTML (cross-platform, simpler) or native SwiftUI window (better macOS feel but platform-specific)?</li><li>Auto-updater in v1 scope or deferred? Simple to add in Tauri; avoids users running stale binaries.</li></ol><h2 id="adoption-path" tabindex="-1">Adoption path <a class="header-anchor" href="#adoption-path" aria-label="Permalink to &quot;Adoption path&quot;">​</a></h2><ol><li>RFC merges.</li><li>Epic task 17.1 — <code>sovereign-desktop</code> scaffold: onboarding, WebView, persistent storage, macOS <code>.dmg</code> CI release; SDK <code>&quot;desktop&quot;</code> environment patch.</li><li>Epic task 17.2 — system tray + OS notifications.</li><li>Epic task 17.3 — deep link scheme (<code>sovereign://</code>).</li><li>Epic task 17.4 — keychain credential storage.</li><li>Epic task 17.5 — auto-updater.</li><li>Epic task 17.6 — Mac App Store distribution (last: requires sandbox review).</li></ol><h2 id="changelog" tabindex="-1">Changelog <a class="header-anchor" href="#changelog" aria-label="Permalink to &quot;Changelog&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Version</th><th>Date</th><th>Change</th></tr></thead><tbody><tr><td>0.1</td><td>June 2026</td><td>Initial draft</td></tr><tr><td>0.2</td><td>July 2026</td><td>Onboarding validation endpoint corrected to the public <code>/api/health</code> (<code>/api/admin/health</code> is admin-key-gated)</td></tr></tbody></table>`,35)])])}const b=t(d,[["render",s]]);export{u as __pageData,b as default};
